import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Services from './components/Services';
import Quotes from './components/Quotes';
import Costs from './components/Costs';
import Settings from './components/Settings';
import { AppView, Service, Cost, Quote, AppSettings } from './types';
import { Menu, X, Maximize, Minimize } from 'lucide-react';

const initialServices: Service[] = [];
const initialCosts: Cost[] = [];
const initialQuotes: Quote[] = [];

const defaultSettings: AppSettings = {
  themeColor: 'blue',
  companyName: 'Yahveh Jireh',
  companyAddress: 'Quiriquina 3738, Comuna Lo Espejo',
  companyPhone: '+56 9 5795 1027',
  whatsappServiceTemplate: '*TALLER: {taller}*\n\nHola {cliente}, tu vehículo {vehiculo} está actualmente en estado: *{estado}*.\n\n💰 Total: ${total}\n💳 Abono: ${abono}\n❗ Pendiente: ${saldo}\n\nDetalles:\n{detalle}',
  whatsappQuoteTemplate: '*COTIZACIÓN #{id}*\n🔧 {taller}\n\nHola {cliente}, aquí tienes el presupuesto para tu {vehiculo}.\n\n📋 *Detalle:*\n{detalle}\n\n💰 *TOTAL: ${total}*\n\n_Válido por {dias} días._'
};

function App() {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);

  // --- Data States ---
  const [services, setServices] = useState<Service[]>(() => {
    try {
      const saved = localStorage.getItem('taller_services');
      return saved ? JSON.parse(saved) : initialServices;
    } catch (error) { return initialServices; }
  });

  const [costs, setCosts] = useState<Cost[]>(() => {
    try {
      const saved = localStorage.getItem('taller_costs');
      return saved ? JSON.parse(saved) : initialCosts;
    } catch (error) { return initialCosts; }
  });

  const [quotes, setQuotes] = useState<Quote[]>(() => {
    try {
      const saved = localStorage.getItem('taller_quotes');
      return saved ? JSON.parse(saved) : initialQuotes;
    } catch (error) { return initialQuotes; }
  });

  const [settings, setSettings] = useState<AppSettings>(() => {
    try {
      const saved = localStorage.getItem('taller_settings');
      return saved ? { ...defaultSettings, ...JSON.parse(saved) } : defaultSettings;
    } catch (error) { return defaultSettings; }
  });

  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Close mobile menu on view change
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [currentView]);

  // Persistence Effects
  useEffect(() => { localStorage.setItem('taller_services', JSON.stringify(services)); }, [services]);
  useEffect(() => { localStorage.setItem('taller_costs', JSON.stringify(costs)); }, [costs]);
  useEffect(() => { localStorage.setItem('taller_quotes', JSON.stringify(quotes)); }, [quotes]);
  useEffect(() => { localStorage.setItem('taller_settings', JSON.stringify(settings)); }, [settings]);

  // Handle Fullscreen toggle
  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  useEffect(() => {
    const handleFullscreenChange = () => { setIsFullscreen(!!document.fullscreenElement); };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const renderView = () => {
    switch(currentView) {
      case AppView.DASHBOARD:
        return <Dashboard services={services} costs={costs} setServices={setServices} setCosts={setCosts} />;
      case AppView.SERVICES:
        return <Services services={services} setServices={setServices} settings={settings} />;
      case AppView.QUOTES:
        return <Quotes quotes={quotes} setQuotes={setQuotes} settings={settings} services={services} setServices={setServices} onNavigate={setCurrentView} />;
      case AppView.COSTS:
        return <Costs costs={costs} setCosts={setCosts} />;
      case AppView.SETTINGS:
        return <Settings 
          settings={settings} 
          setSettings={setSettings} 
          services={services} 
          setServices={setServices} 
          costs={costs}       
          setCosts={setCosts}       
          quotes={quotes}     
          setQuotes={setQuotes}     
        />;
      default:
        return <Dashboard services={services} costs={costs} setServices={setServices} setCosts={setCosts} />;
    }
  };

  const getViewTitle = () => {
    switch(currentView) {
      case AppView.DASHBOARD: return 'Dashboard';
      case AppView.SERVICES: return 'Gestión de Servicios';
      case AppView.QUOTES: return 'Cotizaciones';
      case AppView.COSTS: return 'Control de Costos';
      case AppView.SETTINGS: return 'Configuración';
      default: return 'TallerManager';
    }
  };

  // Helper to get text color based on theme
  const getThemeColorClass = () => {
    switch(settings.themeColor) {
      case 'purple': return 'text-purple-500';
      case 'emerald': return 'text-emerald-500';
      case 'orange': return 'text-orange-500';
      case 'red': return 'text-red-500';
      default: return 'text-blue-500';
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-blue-500/30">
      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm md:hidden" onClick={() => setIsMobileMenuOpen(false)} />
      )}

      {/* Sidebar (Mobile Wrapper) */}
      <div className={`fixed inset-y-0 left-0 z-50 transform ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none`}>
        <Sidebar 
          currentView={currentView} 
          setCurrentView={setCurrentView} 
          onNavigate={() => setIsMobileMenuOpen(false)}
          settings={settings}
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">

        {/* Unified Header */}
        <header className="h-16 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md flex items-center justify-between px-4 md:px-6 shrink-0 sticky top-0 z-30">
          <div className="flex items-center gap-4">
             {/* Mobile Menu Toggle */}
             <button 
               onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} 
               className="md:hidden p-2 -ml-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
             >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
             </button>

             {/* Title */}
             <div>
               <h1 className="md:hidden font-bold text-lg text-white tracking-tight truncate max-w-[200px]">
                 {settings.companyName}
               </h1>
               <h2 className="hidden md:block text-lg font-semibold text-white">{getViewTitle()}</h2>
             </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={toggleFullScreen} 
              className={`p-2.5 rounded-lg transition-all active:scale-95 ${isFullscreen ? 'text-blue-400 bg-blue-500/10' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`} 
              aria-label="Pantalla completa"
            >
               {isFullscreen ? <Minimize size={20} /> : <Maximize size={20} />}
            </button>
          </div>
        </header>

        {/* View Container */}
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 scroll-smooth">
          <div className="max-w-7xl mx-auto h-full">
            {renderView()}
          </div>
        </main>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { Service, Cost, ServicePayment } from '../types';
import { LineChart, Line, XAxis, YAxis, Tooltip as RechartsTooltip, ResponsiveContainer, CartesianGrid, Area, AreaChart } from 'recharts';
import { TrendingUp, TrendingDown, Users, CheckCircle, ArrowLeft, Calendar, Activity, Wallet, FileText, Trophy, Car, Filter, Clock, DollarSign, ChevronDown, ChevronUp, Trash2 } from 'lucide-react';

interface DashboardProps {
  services: Service[];
  setServices: React.Dispatch<React.SetStateAction<Service[]>>;
  costs: Cost[];
  setCosts: React.Dispatch<React.SetStateAction<Cost[]>>;
}

type TimeFilter = 'week' | 'month' | 'all' | 'specific-month';
type DetailViewType = 'income' | 'costs' | null;

const Dashboard: React.FC<DashboardProps> = ({ services, setServices, costs, setCosts }) => {
  const [detailView, setDetailView] = useState<DetailViewType>(null);

  // Drilldown Filters
  const [timeFilter, setTimeFilter] = useState<TimeFilter>('month');
  const [selectedMonthDate, setSelectedMonthDate] = useState<Date>(new Date());
  const [isMonthDropdownOpen, setIsMonthDropdownOpen] = useState(false);

  // --- CHART FILTERS STATE ---
  const [chartMode, setChartMode] = useState<'last_6_months' | 'year' | 'month'>('last_6_months');
  const [chartYear, setChartYear] = useState(new Date().getFullYear());
  const [chartMonth, setChartMonth] = useState(new Date().getMonth());

  // --- Helpers for Selectors ---
  const availableYears = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() - i);
  const monthNames = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
  const shortMonthNames = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

  // Helper to safely format dates avoiding timezone shifts
  const formatDateSafe = (dateStr: string) => {
    if (!dateStr) return '-';
    if (dateStr.includes('T')) {
       return new Date(dateStr).toLocaleDateString('es-CL');
    }
    const parts = dateStr.split('-');
    if (parts.length === 3) {
       return `${parts[2]}/${parts[1]}/${parts[0]}`;
    }
    return new Date(dateStr).toLocaleDateString('es-CL');
  };

  const calculateServiceTotal = (s: Service) => {
    const labor = (s.laborItems || []).reduce((acc, curr) => acc + curr.amount, 0);
    const expenses = (s.expenses || []).reduce((acc, curr) => acc + curr.amount, 0);
    const baseLabor = labor === 0 && s.price > 0 ? s.price : labor; 
    return baseLabor + expenses;
  };

  // --- Generate Financial Events (Income) ---
  const incomeEvents = useMemo(() => {
    // Add 'serviceId' and 'type' to track for deletion
    const events: { id: string, date: string, amount: number, description: string, brand?: string, model?: string, serviceId: string, type: 'payment' | 'legacy_advance' | 'legacy_final' }[] = [];

    services.forEach(service => {
      // 1. Priority: Explicit Payments Array
      if (service.payments && service.payments.length > 0) {
        service.payments.forEach(p => {
          events.push({
            id: p.id,
            date: p.date,
            amount: p.amount,
            description: p.description,
            brand: service.brand,
            model: service.model,
            serviceId: service.id,
            type: 'payment'
          });
        });
      } 
      // 2. Fallback: Legacy Logic
      else {
        if (service.advance && service.advance > 0) {
          events.push({
            id: `${service.id}-advance`,
            date: service.entryDate,
            amount: service.advance,
            description: `Adelanto ${service.plate}`,
            brand: service.brand,
            model: service.model,
            serviceId: service.id,
            type: 'legacy_advance'
          });
        }

        if (service.status === 'completed') {
          const total = calculateServiceTotal(service);
          const balance = total - (service.advance || 0);

          if (balance > 0) {
            events.push({
              id: `${service.id}-final`,
              date: service.entryDate, 
              amount: balance,
              description: `Saldo Final ${service.plate}`,
              brand: service.brand,
              model: service.model,
              serviceId: service.id,
              type: 'legacy_final'
            });
          }
        }
      }
    });
    return events;
  }, [services]);

  // --- Delete Handlers ---
  const handleDeleteItem = (item: any, type: DetailViewType) => {
    if (!confirm('¿Estás seguro de eliminar este registro? Esta acción afectará los totales.')) return;

    if (type === 'costs') {
        // Delete Cost
        setCosts(prev => prev.filter(c => c.id !== item.id));
    } else if (type === 'income') {
        // Delete Income (Service Payment)
        setServices(prev => prev.map(s => {
            if (s.id !== item.serviceId) return s;

            // Clone service to modify
            const updated = { ...s };

            if (item.type === 'payment') {
                // Remove from payments array
                updated.payments = (s.payments || []).filter(p => p.id !== item.id);
            } else if (item.type === 'legacy_advance') {
                // Reset legacy advance
                updated.advance = 0;
            } 
            // Note: 'legacy_final' is calculated, cannot be deleted directly without changing status or logic.
            // We'll skip it or warn user.

            return updated;
        }));
    }
  };

  // --- Generate Last 12 Months ---
  const last12Months = useMemo(() => {
    const months = [];
    const today = new Date();
    for (let i = 0; i < 12; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      months.push(d);
    }
    return months;
  }, []);

  const totalIncome = incomeEvents.reduce((acc, curr) => acc + curr.amount, 0);
  const totalCosts = costs.reduce((acc, curr) => acc + curr.amount, 0);

  // --- CHART DATA LOGIC ---
  const trendData = useMemo(() => {
    const dataMap = new Map<string, { date: string, sortKey: number, income: number, expense: number }>();
    const now = new Date();

    let startDate: Date;
    let endDate: Date;
    let groupBy: 'day' | 'month' = 'day';

    if (chartMode === 'last_6_months') {
        startDate = new Date(now.getFullYear(), now.getMonth() - 5, 1);
        startDate.setHours(0,0,0,0);
        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0);
        endDate.setHours(23,59,59,999);
        groupBy = 'day';
    } else if (chartMode === 'year') {
        startDate = new Date(chartYear, 0, 1);
        endDate = new Date(chartYear, 11, 31, 23, 59, 59);
        groupBy = 'month';
    } else {
        startDate = new Date(chartYear, chartMonth, 1);
        endDate = new Date(chartYear, chartMonth + 1, 0, 23, 59, 59);
        groupBy = 'day';
    }

    if (groupBy === 'month') {
        for(let i=0; i<12; i++) {
             dataMap.set(i.toString(), { 
                 date: shortMonthNames[i], 
                 sortKey: i, 
                 income: 0, 
                 expense: 0 
             });
        }
    }

    const processItem = (dateStr: string, amount: number, type: 'income' | 'expense') => {
        const d = new Date(dateStr);
        if (dateStr.length === 10) { 
           d.setHours(12,0,0,0);
        }

        if (d < startDate || d > endDate) return;

        let key: string;
        let label: string;
        let sortKey: number;

        if (groupBy === 'month') {
            const m = d.getMonth();
            key = m.toString();
            label = shortMonthNames[m];
            sortKey = m;
        } else {
            const day = new Date(d.getFullYear(), d.getMonth(), d.getDate());
            key = day.toISOString();
            label = d.toLocaleDateString('es-CL', { day: '2-digit', month: '2-digit' });
            sortKey = day.getTime();
        }

        if (!dataMap.has(key)) {
            dataMap.set(key, { date: label, sortKey, income: 0, expense: 0 });
        }

        const entry = dataMap.get(key)!;
        if (type === 'income') entry.income += amount;
        else entry.expense += amount;
    };

    incomeEvents.forEach(evt => processItem(evt.date, evt.amount, 'income'));
    costs.forEach(c => processItem(c.date, c.amount, 'expense'));

    return Array.from(dataMap.values()).sort((a, b) => a.sortKey - b.sortKey);
  }, [incomeEvents, costs, chartMode, chartYear, chartMonth]);

  const topBrands = useMemo(() => {
    const counts = services.reduce((acc, curr) => {
      acc[curr.brand] = (acc[curr.brand] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(counts)
      .sort((a, b) => (b[1] as number) - (a[1] as number))
      .slice(0, 3)
      .map(([name, count], index) => ({ name, count, rank: index + 1 }));
  }, [services]);

  const getFilteredData = () => {
    const now = new Date();
    now.setHours(23, 59, 59, 999);

    const oneWeekAgo = new Date(now);
    oneWeekAgo.setDate(now.getDate() - 7);

    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    const isWithinFilter = (dateStr: string) => {
      const d = new Date(dateStr);
      if(dateStr.length === 10) d.setHours(12,0,0,0);
      else d.setHours(12,0,0,0);

      if (timeFilter === 'all') return true;
      if (timeFilter === 'week') return d >= oneWeekAgo && d <= now;
      if (timeFilter === 'month') return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
      if (timeFilter === 'specific-month') {
        return d.getMonth() === selectedMonthDate.getMonth() && d.getFullYear() === selectedMonthDate.getFullYear();
      }
      return true;
    };

    if (detailView === 'income') {
      const filteredIncome = incomeEvents.filter(e => isWithinFilter(e.date));
      filteredIncome.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      const total = filteredIncome.reduce((acc, s) => acc + s.amount, 0);
      return { items: filteredIncome, total, type: 'income' };
    } else {
      const filteredCosts = costs.filter(c => isWithinFilter(c.date));
      filteredCosts.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      const total = filteredCosts.reduce((acc, c) => acc + c.amount, 0);
      return { items: filteredCosts, total, type: 'costs' };
    }
  };

  const filteredData = getFilteredData();

  const handleMonthSelect = (date: Date) => {
    setSelectedMonthDate(date);
    setTimeFilter('specific-month');
    setIsMonthDropdownOpen(false);
  };

  const capitalize = (s: string) => s.charAt(0).toUpperCase() + s.slice(1);

  const StatCard = ({ title, value, icon: Icon, variant, onClick, isClickable }: any) => {
    const variants = {
      success: { wrapper: 'from-emerald-900/40 to-slate-900', border: 'border-emerald-500/30', iconBox: 'bg-emerald-500/20 text-emerald-400', text: 'text-white', glow: 'group-hover:shadow-emerald-500/10' },
      danger: { wrapper: 'from-rose-900/40 to-slate-900', border: 'border-rose-500/30', iconBox: 'bg-rose-500/20 text-rose-400', text: 'text-white', glow: 'group-hover:shadow-rose-500/10' },
      info: { wrapper: 'from-blue-900/40 to-slate-900', border: 'border-blue-500/30', iconBox: 'bg-blue-500/20 text-blue-400', text: 'text-white', glow: 'group-hover:shadow-blue-500/10' },
      purple: { wrapper: 'from-violet-900/40 to-slate-900', border: 'border-violet-500/30', iconBox: 'bg-violet-500/20 text-violet-400', text: 'text-white', glow: 'group-hover:shadow-violet-500/10' }
    };
    const styles = variants[variant as 'success' | 'danger' | 'info' | 'purple'] || variants.info;

    return (
      <div onClick={onClick} className={`relative overflow-hidden p-4 rounded-xl border ${styles.border} bg-gradient-to-br ${styles.wrapper} shadow-lg transition-all duration-300 group ${isClickable ? `cursor-pointer hover:scale-[1.01] ${styles.glow}` : ''}`}>
        <div className={`absolute -right-4 -bottom-4 opacity-10 transform -rotate-12 transition-transform duration-500 group-hover:scale-110 pointer-events-none ${styles.text}`}><Icon size={80} /></div>
        <div className="relative z-10 flex items-center justify-between">
          <div className="space-y-1"><p className="text-slate-400 text-xs font-bold uppercase tracking-wider">{title}</p><h3 className="text-2xl font-bold text-white tracking-tight">{value}</h3></div>
          <div className={`p-2.5 rounded-lg ${styles.iconBox} shadow-inner`}><Icon size={20} /></div>
        </div>
      </div>
    );
  };

  if (detailView) {
     const isIncome = detailView === 'income';
     const themeColor = isIncome ? 'emerald' : 'rose';
     let filterLabel = 'Histórico Total';
     if (timeFilter === 'week') filterLabel = 'Última Semana';
     if (timeFilter === 'month') filterLabel = 'Este Mes';
     if (timeFilter === 'specific-month') filterLabel = capitalize(selectedMonthDate.toLocaleDateString('es-CL', { month: 'long', year: 'numeric' }));

     return (
      <div className="space-y-6 animate-fade-in pb-10">
        <div className="flex items-center justify-between">
          <button onClick={() => setDetailView(null)} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors group"><div className="p-2 bg-slate-800 rounded-lg group-hover:bg-slate-700 transition-colors"><ArrowLeft size={20} /></div><span className="font-medium">Volver al Dashboard</span></button>
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-1 space-y-4">
             <div className={`p-6 rounded-2xl bg-gradient-to-br from-${themeColor}-900/40 to-slate-900 border border-${themeColor}-500/30 shadow-lg`}>
                <h3 className={`text-${themeColor}-400 font-bold uppercase tracking-wider text-sm mb-2`}>{isIncome ? 'Total Ingresos' : 'Total Gastos'}</h3>
                <div className="text-4xl font-bold text-white mb-2">${filteredData.total.toLocaleString('es-CL')}</div>
                <div className="text-slate-400 text-sm flex items-center gap-2"><Filter size={14} /> Filtro: {filterLabel}</div>
             </div>
             <div className="bg-slate-800 p-2 rounded-xl border border-slate-700 flex flex-col gap-1 relative z-20">
                <button onClick={() => { setTimeFilter('week'); setIsMonthDropdownOpen(false); }} className={`px-4 py-3 rounded-lg text-sm font-medium transition-colors flex items-center gap-3 ${timeFilter === 'week' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-white hover:bg-slate-700/50'}`}><Clock size={16} /> Última Semana</button>
                <button onClick={() => { setTimeFilter('month'); setIsMonthDropdownOpen(false); }} className={`px-4 py-3 rounded-lg text-sm font-medium transition-colors flex items-center gap-3 ${timeFilter === 'month' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-white hover:bg-slate-700/50'}`}><Activity size={16} /> Este Mes (Actual)</button>
                <div className="relative">
                   <button onClick={() => setIsMonthDropdownOpen(!isMonthDropdownOpen)} className={`w-full px-4 py-3 rounded-lg text-sm font-medium transition-colors flex items-center justify-between gap-3 ${timeFilter === 'specific-month' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-white hover:bg-slate-700/50'}`}><div className="flex items-center gap-3"><Calendar size={16} /> {timeFilter === 'specific-month' ? capitalize(selectedMonthDate.toLocaleDateString('es-CL', { month: 'long', year: 'numeric' })) : 'Por Mes...'}</div>{isMonthDropdownOpen ? <ChevronUp size={16} /> : <ChevronDown size={16} />}</button>
                   {isMonthDropdownOpen && (
                     <div className="absolute top-full left-0 right-0 mt-2 bg-slate-800 border border-slate-600 rounded-lg shadow-xl max-h-60 overflow-y-auto z-50 animate-fade-in">
                       {last12Months.map((date, idx) => (
                         <button key={idx} onClick={() => handleMonthSelect(date)} className={`w-full text-left px-4 py-2 text-sm hover:bg-slate-700 transition-colors border-b border-slate-700/50 last:border-0 ${timeFilter === 'specific-month' && date.getMonth() === selectedMonthDate.getMonth() && date.getFullYear() === selectedMonthDate.getFullYear() ? 'text-blue-400 font-bold bg-slate-700/50' : 'text-slate-300'}`}>{capitalize(date.toLocaleDateString('es-CL', { month: 'long', year: 'numeric' }))}</button>
                       ))}
                     </div>
                   )}
                </div>
                <div className="border-t border-slate-700 my-1"></div>
                <button onClick={() => { setTimeFilter('all'); setIsMonthDropdownOpen(false); }} className={`px-4 py-3 rounded-lg text-sm font-medium transition-colors flex items-center gap-3 ${timeFilter === 'all' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400 hover:text-white hover:bg-slate-700/50'}`}><TrendingUp size={16} /> Todo el Historial</button>
             </div>
          </div>
          <div className="lg:col-span-2 bg-slate-800 rounded-2xl border border-slate-700 shadow-xl flex flex-col overflow-hidden">
             <div className="p-4 border-b border-slate-700 bg-slate-900/50 flex justify-between items-center">
                <h2 className="text-lg font-bold text-white flex items-center gap-2">{isIncome ? <Wallet size={20} className="text-emerald-500" /> : <TrendingDown size={20} className="text-rose-500" />} Detalle de Movimientos</h2>
                <span className="text-xs font-mono text-slate-500 bg-slate-900 px-2 py-1 rounded">{filteredData.items.length} registros</span>
             </div>
             <div className="flex-1 overflow-y-auto max-h-[500px] p-2 space-y-2">
               {filteredData.items.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-12 text-slate-500"><FileText size={48} className="mb-4 opacity-20" /><p>No hay registros para este periodo.</p></div>
               ) : (
                 filteredData.items.map((item: any) => (
                    <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-900/30 hover:bg-slate-700/30 rounded-xl border border-slate-700/50 transition-colors group">
                       <div className={`p-3 rounded-full shrink-0 ${isIncome ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>{isIncome ? <Users size={18} /> : <DollarSign size={18} />}</div>
                       <div className="flex-1 min-h-0">
                          <div className="font-medium text-white truncate">{isIncome ? item.clientName || item.description : item.description}</div>
                          <div className="text-xs text-slate-500 flex items-center gap-2"><span>{formatDateSafe(isIncome ? item.date : item.date)}</span>{isIncome && item.brand && (<><span className="w-1 h-1 rounded-full bg-slate-600"></span><span className="uppercase">{item.brand} {item.model}</span></>)}</div>
                       </div>
                       <div className="text-right flex items-center gap-4">
                          <div>
                             <div className={`font-bold ${isIncome ? 'text-emerald-400' : 'text-rose-400'}`}>{isIncome ? '+' : '-'}${item.amount.toLocaleString('es-CL')}</div>
                             {isIncome && <div className="text-[10px] text-slate-500 uppercase tracking-wide">Pago Recibido</div>}
                          </div>
                          {item.type !== 'legacy_final' && (
                              <button onClick={() => handleDeleteItem(item, detailView)} className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-colors" title="Eliminar registro">
                                  <Trash2 size={16} />
                              </button>
                          )}
                       </div>
                    </div>
                 ))
               )}
             </div>
          </div>
        </div>
      </div>
     );
  }

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="mb-2"><h2 className="text-2xl font-bold text-white">Resumen General</h2><p className="text-slate-400 text-sm">Vista rápida del estado de tu taller.</p></div>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <StatCard title="Ingresos Totales" value={`$${totalIncome.toLocaleString('es-CL')}`} icon={Wallet} variant="success" isClickable={true} onClick={() => { setDetailView('income'); setTimeFilter('month'); }} />
        <StatCard title="Gastos Totales" value={`$${totalCosts.toLocaleString('es-CL')}`} icon={TrendingDown} variant="danger" isClickable={true} onClick={() => { setDetailView('costs'); setTimeFilter('month'); }} />
        <StatCard title="Clientes Activos" value={services.length.toString()} icon={Users} variant="info" />
        <StatCard title="Servicios Listos" value={services.filter(s => s.status === 'completed').length.toString()} icon={CheckCircle} variant="purple" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-lg flex flex-col">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
            <h3 className="text-lg font-bold text-white flex items-center gap-2"><Activity className="text-blue-500" size={20} /> Tendencia Financiera</h3>
            <div className="flex flex-wrap items-center gap-2">
              <div className="relative">
                <select value={chartMode} onChange={(e) => setChartMode(e.target.value as any)} className="bg-slate-900 border border-slate-600 rounded-lg py-1.5 pl-3 pr-8 text-xs text-white appearance-none focus:outline-none focus:border-blue-500 cursor-pointer">
                  <option value="last_6_months">Últimos 6 Meses</option>
                  <option value="year">Por Año</option>
                  <option value="month">Por Mes</option>
                </select>
                <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400"><ChevronDown size={14} /></div>
              </div>
              {chartMode !== 'last_6_months' && (
                <div className="relative">
                  <select value={chartYear} onChange={(e) => setChartYear(Number(e.target.value))} className="bg-slate-900 border border-slate-600 rounded-lg py-1.5 pl-3 pr-8 text-xs text-white appearance-none focus:outline-none focus:border-blue-500 cursor-pointer">{availableYears.map(y => <option key={y} value={y}>{y}</option>)}</select>
                  <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400"><ChevronDown size={14} /></div>
                </div>
              )}
              {chartMode === 'month' && (
                <div className="relative">
                   <select value={chartMonth} onChange={(e) => setChartMonth(Number(e.target.value))} className="bg-slate-900 border border-slate-600 rounded-lg py-1.5 pl-3 pr-8 text-xs text-white appearance-none focus:outline-none focus:border-blue-500 cursor-pointer w-24">{monthNames.map((m, i) => <option key={i} value={i}>{m}</option>)}</select>
                   <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400"><ChevronDown size={14} /></div>
                </div>
              )}
            </div>
          </div>
          <div className="flex-1 min-h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={trendData}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/><stop offset="95%" stopColor="#10b981" stopOpacity={0}/></linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#ef4444" stopOpacity={0.3}/><stop offset="95%" stopColor="#ef4444" stopOpacity={0}/></linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} opacity={0.3} />
                <XAxis dataKey="date" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} dy={10} minTickGap={10} />
                <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `$${val/1000}k`} />
                <RechartsTooltip contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', color: '#fff', borderRadius: '8px' }} formatter={(value: number) => [`$${value.toLocaleString('es-CL')}`, '']} />
                <Area type="monotone" dataKey="income" name="Ingresos" stroke="#10b981" strokeWidth={2} fillOpacity={1} fill="url(#colorIncome)" animationDuration={500} />
                <Area type="monotone" dataKey="expense" name="Gastos" stroke="#ef4444" strokeWidth={2} fillOpacity={1} fill="url(#colorExpense)" animationDuration={500} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-lg flex flex-col">
          <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><Trophy className="text-yellow-500" size={20} /> Top 3 Marcas</h3>
          <div className="flex-1 space-y-5">
             {topBrands.length === 0 ? <div className="text-center text-slate-500 text-sm py-8">Sin datos suficientes</div> : topBrands.map((brand) => (
                   <div key={brand.name} className="relative group">
                      <div className="flex justify-between items-center mb-1 relative z-10">
                         <div className="flex items-center gap-3">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${brand.rank === 1 ? 'bg-yellow-500 text-black shadow-yellow-500/50 shadow-sm' : brand.rank === 2 ? 'bg-slate-300 text-black' : 'bg-orange-700 text-white'}`}>{brand.rank}</div>
                            <span className="text-slate-200 font-medium">{brand.name}</span>
                         </div>
                         <div className="flex items-center gap-2"><Car size={14} className="text-slate-500" /><span className="text-white font-bold">{brand.count}</span></div>
                      </div>
                      <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden"><div className={`h-full rounded-full transition-all duration-1000 ease-out ${brand.rank === 1 ? 'bg-yellow-500' : brand.rank === 2 ? 'bg-slate-400' : 'bg-orange-600'}`} style={{ width: `${(brand.count / (topBrands[0].count || 1)) * 100}%` }}></div></div>
                   </div>
                ))}
          </div>
          <div className="mt-auto pt-4 border-t border-slate-700/50 text-center"><p className="text-xs text-slate-500">Basado en el historial de revisiones</p></div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
