                               ))
                            ) : (
                               <div className="flex justify-between p-2 border-b border-slate-700/30 text-xs"><span className="text-slate-300 pl-2">Mano de Obra Base</span><span className="text-slate-200">${formatCLP(service.price)}</span></div>
