      {showHistory && (
        <div className="space-y-4">
          {displayedServices.length === 0 ? (
             <div className="py-12 text-center text-slate-500 bg-slate-800/30 rounded-xl border border-dashed border-slate-700">No hay servicios en el historial.</div>
