                                      <a href={photo} download={`evidencia_${viewingPhotoService.plate}_${idx}.jpg`} className="p-2 bg-blue-600 rounded-full text-white hover:bg-blue-500"><Download size={20}/></a>
                                      <button onClick={() => deletePhoto(viewingPhotoService.id, idx)} className="p-2 bg-red-600 rounded-full text-white hover:bg-red-500"><Trash2 size={20}/></button>
                                  </div>
                              </div>
                          ))}
                      </div>
