        amount: service.price
      }];
    }

    setNewService({ 
      ...service, 
      laborItems: laborItems,
      expenses: service.expenses || [],
      payments: service.payments || [],
      photos: service.photos || []
    });
    setIsEditing(true);
    setFoundExistingCar(true);
    setIsModalOpen(true);
  };

  const resetForm = () => {
    setNewService({ 
      status: 'pending', 
