                    <FilePenLine size={20} /> <span className="hidden sm:inline">Continuar Borrador</span>
                    <div onClick={discardDraft} className="p-1 hover:bg-yellow-800 rounded-full ml-1" title="Descartar borrador"><X size={14}/></div>
                  </button>
