                                      <button onClick={() => deletePhoto(viewingPhotoService.id, idx)} className="p-2 bg-red-600 rounded-full text-white hover:bg-red-500" title="Borrar"><Trash2 size={20}/></button>
                                  </div>
                              </div>
                          ))}
                      </div>
