    ];

    const rows = quotes.map(q => {
      const allItems = [...(q.laborItems || []), ...(q.expenseItems || []), ...(q.items || [])];
      const details = allItems.map(i => `(${i.quantity}) ${i.description} $${i.unitPrice}`).join(' | ');

      return [
        q.id,
        new Date(q.date).toLocaleDateString(),
