        const file = new File([blob], `foto_taller_${index}.jpg`, { type: blob.type });

        if (navigator.share && navigator.canShare({ files: [file] })) {
            await navigator.share({
                files: [file],
                title: 'Foto del Servicio',
                text: 'Adjunto evidencia fotográfica del taller.'
            });
